from flask import Flask, request, jsonify, g
from flask_httpauth import HTTPBasicAuth
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
auth = HTTPBasicAuth()

# Dummy user database for demonstration purposes
users_db = {
    'admin': {'password': generate_password_hash('adminpass'), 'role': 'admin'},
    'user1': {'password': generate_password_hash('user1pass'), 'role': 'user'}
}

# User roles and their permissions
role_permissions = {
    'admin': ['email', 'username', 'role', 'account_status', 'subscription_tier'],
    'moderator': ['email', 'username', 'role', 'account_status'],
    'user': ['email']
}

# Load user from database (for demonstration purposes)
def load_user(user_id):
    if user_id in users_db:
        return {'id': user_id, **users_db[user_id]}
    return None

# User loader callback
@auth.verify_password
def verify_password(username, password):
    if username in users_db and check_password_hash(users_db[username]['password'], password):
        g.current_user = load_user(username)
        return True
    return False

# Update user endpoint
@app.route('/api/users/<user_id>', methods=['PUT'])
@auth.login_required
def update_user(user_id):
    if not g.current_user or g.current_user['role'] != 'admin':
        return jsonify({'message': 'Unauthorized'}), 403

    user = load_user(user_id)
    if not user:
        return jsonify({'message': 'User not found'}), 404

    data = request.get_json()
    updateable_fields = role_permissions[g.current_user['role']]

    for key, value in data.items():
        if key in updateable_fields:
            user[key] = value

    # In a real application, you would save the updated user to your database here
    return jsonify(user), 200

if __name__ == '__main__':
    app.run(debug=True)